import React, { useState } from 'react';
import './ChatModal.css';

const ChatModal = ({ onClose }) => {
  const [messages, setMessages] = useState([
    {
      id: 1,
      user: 'User123',
      message: 'Hi, how are you doing?',
      time: '2 min ago',
      isSupport: false
    },
    {
      id: 2,
      user: 'Support',
      message: 'We been feeling some stress about things lately.',
      time: '1 min ago',
      isSupport: true
    },
    {
      id: 3,
      user: 'User123',
      message: "I'm here to listen. What's been going on?",
      time: 'now',
      isSupport: false
    }
  ]);
  
  const [newMessage, setNewMessage] = useState('');

  const handleSendMessage = (e) => {
    e.preventDefault();
    if (newMessage.trim()) {
      const message = {
        id: messages.length + 1,
        user: 'You',
        message: newMessage,
        time: 'now',
        isSupport: false
      };
      setMessages([...messages, message]);
      setNewMessage('');
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal chat-modal" onClick={(e) => e.stopPropagation()}>
        <button className="modal-close" onClick={onClose}>×</button>
        
        <div className="chat-header">
          <h2>Chat</h2>
          <button className="more-options">⋯</button>
        </div>

        <div className="chat-messages">
          {messages.map((msg) => (
            <div key={msg.id} className={`message ${msg.isSupport ? 'support' : 'user'}`}>
              <div className="message-header">
                <span className="message-user">
                  {msg.isSupport ? '👤' : '🟢'} {msg.user}
                </span>
                <span className="message-time">{msg.time}</span>
              </div>
              <div className="message-content">{msg.message}</div>
              <div className="message-actions">
                <button className="action-btn">💬 Support</button>
                <button className="action-btn">👍 {msg.isSupport ? 'Helpful' : 'Follow'}</button>
              </div>
            </div>
          ))}
        </div>

        <form onSubmit={handleSendMessage} className="chat-input-form">
          <input
            type="text"
            value={newMessage}
            onChange={(e) => setNewMessage(e.target.value)}
            placeholder="Type a message..."
            className="chat-input"
          />
          <button type="submit" className="send-btn">Send</button>
        </form>
      </div>
    </div>
  );
};

export default ChatModal;
